-- в”Ђв”Ђ Zoom Phone в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based business phone system (VoIP) from Zoom offering metered or unlimited calling plans, auto-attendants, call queues, and AI call summaries.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From approximately 10.50 dollars per user per month billed annually$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$5000-10000 employees$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zoom Phone Review: VoIP Pricing and Features (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Zoom Phone's cloud calling plans work, including Metered, Unlimited, and Global Select pricing, auto-attendants, and AI call features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zoom Phone is the cloud business phone (VoIP) product from Zoom Video Communications, the video conferencing company founded in 2011 by Eric Yuan and headquartered in San Jose, California. While it shares infrastructure and branding with Zoom's flagship video meeting product, Zoom Phone is a distinct, separately priced offering focused on replacing traditional business phone systems with cloud-based calling, SMS, and voicemail. It provides features such as auto-attendants, multi-level call routing, call queues, voicemail transcription, and integration with the wider Zoom Workplace suite including Team Chat and Meetings. As part of Zoom's broader AI Companion rollout, Zoom Phone includes AI-powered post-call summaries, task extraction, and voicemail prioritization on eligible plans. Zoom Phone is sold both as a standalone product and bundled into higher Zoom Workplace tiers. Standalone plans include US and Canada Metered, starting around 10.50 dollars per user per month billed annually, which charges pay-as-you-go rates for outbound calls and suits organizations with low call volume; US and Canada Unlimited, around 16 dollars per user per month annually (18 dollars month-to-month), which adds unlimited domestic calling, advanced call queue management, and multi-level auto-attendant customization; and Global Select, around 20 dollars per user per month annually (25 dollars month-to-month), which provides phone numbers and unlimited calling across a large list of supported countries for international teams. Zoom also bundles Zoom Phone into Workplace plans: Pro Plus, billed around 20.50 dollars per user per month annually, adds AI Companion call transcription and 10GB of cloud recording storage, while Business Plus, around 24.50 dollars per user per month annually, supports up to 250 users with expanded meeting capacity and native CRM automation for platforms like Salesforce. An add-on Power Pack, around 25 dollars per user per month, unlocks real-time queue analytics, wallboard monitoring, and a desktop receptionist console for high-volume call centers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '96e91f43-5f01-4104-b90d-be66d79b5e88';

