-- в”Ђв”Ђ ZOT OCI Registry в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Open-source, vendor-neutral OCI-native container image registry delivered as a single stateless binary, backed by CNCF Sandbox status.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zot OCI Registry Review: Features and Setup Guide (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn about Zot, the open-source OCI-native container registry, its single-binary architecture, key features, and CNCF Sandbox status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zot (also referenced as ZOT OCI Registry) is an open-source, vendor-neutral, OCI-native container image and artifact registry, developed under the project-zot organization on GitHub and distributed under the Apache 2.0 license. Zot strictly follows the OCI Distribution Specification and OCI Image Specification, storing images purely in OCI format rather than relying on a proprietary internal format, which makes it interoperable with standard tooling like Docker, Podman, and Helm. The project was accepted as a CNCF (Cloud Native Computing Foundation) Sandbox Project on December 13, 2022, and the Linux Foundation holds trademark rights over the project name; Cisco is noted as a sponsor and adopter within the project's ecosystem. Zot is architected as a single, statically built binary with no external dependencies, allowing it to run without elevated system privileges on platforms ranging from cloud servers to edge devices like a Raspberry Pi. Despite its lightweight footprint, Zot bundles a broad set of registry capabilities directly into the binary, including vulnerability and security scanning, authentication (HTTP Basic, LDAP, and HTTP Bearer token), authorization, garbage collection, image deduplication, replication, and caching. It also supports OCI artifacts beyond container images, such as Helm charts, software bill of materials (SBOM) files, and image signatures, positioning it as a general-purpose OCI artifact store rather than a container-only registry. Zot offers two build variants: a full, feature-complete build and a minimal, security-focused build for environments that want the smallest possible attack surface. As an open-source, community-governed project rather than a commercial company, Zot has no founding year, headquarters, company size, or commercial pricing in the traditional sense; it is free to self-host and use under its Apache 2.0 license, with active community support through GitHub, Slack, and project documentation at zotregistry.dev.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172';

