INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Gantt charts$q$, $q$Visual timelines that map task dependencies and flag deviations between planned and actual progress.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Time tracking$q$, $q$Built-in timers for billable and non-billable hours with automatic invoice generation via Zoho Invoice.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Task automation (Blueprints)$q$, $q$Drag-and-drop workflow builder to automate recurring, multi-step processes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Custom fields and layouts$q$, $q$Configurable statuses, fields, and views to match a team's existing workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$50-plus integrations$q$, $q$Native connections to Slack, GitHub, Jira, Dropbox, and other Zoho apps like CRM and Books.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Mobile apps$q$, $q$iOS and Android apps for managing tasks and tracking time on the go.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Resource and workload reports$q$, $q$Dashboards showing task status, workload distribution, and project health.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Enterprise security$q$, $q$ISO 27001-certified infrastructure with SSO and custom domain support on higher plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Generous free tier for small teams (up to 5 users)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Deep native integration with the wider Zoho One suite$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Competitive pricing compared to Asana, Monday.com, and similar tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Strong Gantt chart and time tracking functionality out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$15-day free trial on all paid plans with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Interface can feel dated compared to newer project management tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Advanced automation and reporting are locked behind higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Read-only user limits and workflow execution caps vary by plan and can require upgrades for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Best value is realized when paired with other Zoho apps, less compelling as a standalone tool$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Is Zoho Projects free?$q$, $q$Yes, Zoho Projects offers a Free plan for up to 5 users, 3 projects, and 5GB of storage with no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$How much does Zoho Projects cost?$q$, $q$Paid plans start around 4 to 5 dollars per user per month for Premium and scale up to around 15 dollars per user per month for the Ultimate plan, with lower rates on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Does Zoho Projects have Gantt charts?$q$, $q$Yes, Gantt charts are a core feature, showing task dependencies and highlighting discrepancies between planned and actual progress.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Does Zoho Projects integrate with other tools?$q$, $q$Yes, it supports over 50 integrations including Slack, GitHub, Jira, and Dropbox, plus native integration with other Zoho applications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Can Zoho Projects track billable hours?$q$, $q$Yes, it includes built-in time tracking with timers for billable and non-billable hours and can generate invoices via Zoho Invoice.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Is there a mobile app for Zoho Projects?$q$, $q$Yes, Zoho Projects has mobile apps for both iOS and Android.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$What is the difference between Premium and Enterprise plans?$q$, $q$Enterprise adds features like custom domains, single sign-on, more read-only users, and higher workflow automation limits compared to Premium.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Does Zoho Projects offer a free trial?$q$, $q$Yes, all paid plans include a 15-day free trial with no credit card required.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Cross-functional project planning$q$, $q$Teams use Gantt charts and dependencies to plan multi-phase projects and track progress against deadlines.$q$, $q$Project managers and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Client billing and time tracking$q$, $q$Agencies track billable hours per task and generate client invoices directly through Zoho Invoice integration.$q$, $q$Agencies and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Zoho ecosystem workflows$q$, $q$Organizations already using Zoho CRM, Books, or Desk extend project tracking natively without adopting a separate platform.$q$, $q$Existing Zoho One customers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Free$q$, $q$0 dollars$q$, $q$n/a$q$, NULL, $q$["Up to 5 users","3 projects","5GB storage","Basic task management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Premium$q$, $q$Approximately 4-5 dollars per user per month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited projects","Custom views","Task blueprints","Time tracking","Multi-level approvals","5,000 workflow executions per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Enterprise$q$, $q$Approximately 9-10 dollars per user per month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Premium","10 read-only users","Custom domain","Single sign-on","50,000 workflow executions per month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Ultimate$q$, $q$Approximately 15 dollars per user per month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Enterprise","15GB storage per user (minimum 150GB per org)","100 read-only users","100 tools","500,000 workflow executions per month"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$overview$q$, $q$What Is Zoho Projects$q$, 2, ARRAY[$q$Zoho Projects is a web-based project management application from Zoho Corporation, designed to help teams plan, execute, and track projects collaboratively. It combines task management, Gantt charts, time tracking, and workflow automation in a single platform aimed at dynamic and often globally distributed teams.$q$, $q$As part of the broader Zoho software suite, Zoho Projects is built to work natively with other Zoho applications such as Zoho CRM, Zoho Books, and Zoho Invoice, making it a natural fit for organizations already standardized on Zoho tools, while still supporting 50-plus external integrations including Slack, GitHub, Jira, and Dropbox.$q$, $q$The platform emphasizes flexibility through custom fields, statuses, layouts, and task blueprints so teams can adapt the software to their existing processes rather than forcing a rigid methodology.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gantt charts provide visual timelines showing task dependencies and highlighting gaps between planned and actual progress, helping project managers spot schedule risk early.$q$, $q$Time tracking includes built-in timers for logging billable and non-billable hours, with the ability to generate invoices directly through integration with Zoho Invoice.$q$, $q$Task automation uses a drag-and-drop workflow builder (Blueprints) to standardize repetitive processes, reducing manual handoffs between team members.$q$, $q$Reporting and dashboards give visibility into resource utilization, task status, and project health, while mobile apps for iOS and Android let teams manage projects remotely.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho Projects offers a Free plan for up to 5 users, 3 projects, and 5GB of storage with no credit card required.$q$, $q$Paid plans include Premium (around 4 to 5 dollars per user per month), Enterprise (around 9 to 10 dollars per user per month, the most popular tier), and Ultimate (around 15 dollars per user per month), each unlocking more storage, automation executions, and administrative controls such as custom domains and single sign-on.$q$, $q$Annual billing reduces the effective per-user cost compared with monthly billing, and every paid plan comes with a 15-day free trial.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Multi-board job posting$q$, $q$Publish job openings to 75-plus job boards simultaneously from a single dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Candidate pipeline tracking$q$, $q$Move candidates through customizable stages with analytics on pipeline performance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$AI-powered sourcing and screening (Zia)$q$, $q$Sourcing Bot, Screening Bot, and AI candidate matching to accelerate shortlisting on Professional and Enterprise plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Client and vendor management$q$, $q$Staffing Agency edition tools for managing external client relationships and vendor portals.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Virtual recruitment support$q$, $q$Remote interviews, background checks, and candidate assessments built into the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Workflow automation$q$, $q$Custom automation to move candidates from interview stage to onboarding.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$50-plus integrations$q$, $q$Connects with Slack, LinkedIn, Outlook, Zoho CRM, and other business tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Mobile apps$q$, $q$iOS and Android apps for managing candidates and communications on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Two purpose-built editions for in-house HR versus staffing agencies$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Extensive job board distribution network (75-plus boards)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$AI-powered candidate matching and screening on higher tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Native integration with Zoho CRM and the broader Zoho suite$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$15-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Free plan is very limited (one active job, no AI or resume parsing)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$AI features are restricted to Professional and Enterprise tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Add-ons like video interviews and client portals can push real costs well above sticker price$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Two-edition structure (Corporate HR vs Staffing Agency) can be confusing to first-time buyers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Is Zoho Recruit free?$q$, $q$Zoho Recruit has a free plan, but it is limited to one active job, 256MB of storage, and no resume parsing, AI, or integrations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$How much does Zoho Recruit cost?$q$, $q$Paid plans typically start around 25 dollars per recruiter per month for Standard and scale up to around 75 dollars per recruiter per month for Enterprise, billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$What is the difference between Corporate HR and Staffing Agency editions?$q$, $q$Corporate HR is built for in-house teams hiring for their own company with fewer active job limits, while Staffing Agency adds client and vendor management tools and supports far more active jobs for external placements.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Does Zoho Recruit have AI features?$q$, $q$Yes, Zoho added AI tools through its Zia engine in late 2025, including Sourcing Bot, Screening Bot, and AI candidate matching, available on Professional and Enterprise tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Does Zoho Recruit post to job boards?$q$, $q$Yes, it can distribute job postings to more than 75 job boards simultaneously.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Does Zoho Recruit integrate with Zoho CRM?$q$, $q$Yes, it integrates natively with Zoho CRM and other Zoho applications, plus external tools like Slack, LinkedIn, and Outlook.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Is there a free trial for Zoho Recruit?$q$, $q$Yes, Zoho Recruit offers a 15-day free trial with no credit card required.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Who uses Zoho Recruit?$q$, $q$Both in-house HR teams building internal talent pipelines and staffing or recruiting agencies placing candidates with external clients.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Internal talent acquisition$q$, $q$In-house HR teams use the Corporate HR edition to source, screen, and hire candidates for their own organization.$q$, $q$In-house HR and talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Agency candidate placement$q$, $q$Staffing and recruiting agencies use the Staffing Agency edition to manage client relationships and place candidates with external employers.$q$, $q$Staffing agencies and recruiting firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$AI-assisted candidate shortlisting$q$, $q$Recruiters use Zia-powered Sourcing Bot and Screening Bot to quickly narrow large applicant pools to qualified candidates.$q$, $q$High-volume recruiting teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Free$q$, $q$0 dollars$q$, $q$n/a$q$, NULL, $q$["1 active job","256MB storage","Limited email templates","No AI or resume parsing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Standard$q$, $q$Approximately 25 dollars per user per month$q$, $q$annual (monthly available at higher rate)$q$, NULL, $q$["10-20 active jobs (Corporate HR) or up to 100 (Staffing Agency)","Resume parsing","Basic reporting","Standard integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Professional (Staffing Agency edition)$q$, $q$Approximately 50 dollars per user per month$q$, $q$annual$q$, NULL, $q$["AI candidate matching (Zia)","Sourcing Bot and Screening Bot","Client management tools","Higher active job limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Enterprise$q$, $q$Approximately 50-75 dollars per user per month$q$, $q$annual$q$, NULL, $q$["Highest active job limits (up to 750 for Staffing Agency)","AI tools included","Client and vendor portals","Advanced dashboards and reports"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$overview$q$, $q$What Is Zoho Recruit$q$, 2, ARRAY[$q$Zoho Recruit is a cloud-based recruitment platform that combines applicant tracking system (ATS) functionality with candidate relationship management (CRM), helping organizations manage the entire talent pipeline from sourcing through onboarding.$q$, $q$The product is split into two editions built for different buyers: Corporate HR, for internal talent acquisition teams, and Staffing Agency, for recruiting and search firms placing candidates with external clients. Each edition has its own plan structure and feature set at similar price points.$q$, $q$Zoho Recruit is part of the larger Zoho software suite and integrates natively with Zoho CRM and other Zoho apps, while also connecting to external tools like Slack, LinkedIn, and Outlook.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Job posting automation lets recruiters publish openings to 75-plus job boards at once, reducing manual posting work across multiple sites.$q$, $q$Candidate tracking follows applicants through customizable pipeline stages with analytics on time-to-fill and source effectiveness.$q$, $q$AI tools powered by Zoho's Zia engine, including Sourcing Bot, Screening Bot, and candidate matching, were added in late 2025 on Professional and Enterprise tiers.$q$, $q$Staffing Agency-specific tools include client and vendor portals, formatted resumes, and multi-org support for agencies managing multiple client relationships.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho Recruit offers a limited free plan (one active job, 256MB storage, no AI or resume parsing) alongside paid Standard, Professional, and Enterprise tiers priced per recruiter per month.$q$, $q$Corporate HR plans run Standard around 25 dollars and Enterprise around 50 dollars per user per month billed annually, with fewer active job limits than the Staffing Agency edition.$q$, $q$Staffing Agency plans run Standard around 25 dollars, Professional around 50 dollars, and Enterprise around 75 dollars per user per month billed annually, with monthly billing typically about 20 percent higher and optional add-ons like video interviews and client portals adding to total cost.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$SmartQ predictive scheduling$q$, $q$Recommends optimal post times based on historical audience engagement patterns.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Social listening and monitoring$q$, $q$Tracks brand mentions, hashtags, and conversations to surface leads and sentiment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Multi-channel publishing$q$, $q$Schedules and publishes to Instagram, Facebook, LinkedIn, X, TikTok, Pinterest, YouTube, and more.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Visual analytics and custom reports$q$, $q$Engagement, traffic, and click-distribution reporting with exportable custom reports.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Content approval workflows$q$, $q$Team review and approval steps before posts go live, available on Professional and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$CRM and helpdesk integration$q$, $q$Connects with Zoho CRM and Zoho Desk to link social activity to sales and support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Agency client management$q$, $q$Client portals, branded logins, and scheduled reporting for agencies managing multiple brands.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Bulk scheduling and media library$q$, $q$Upload and schedule content in bulk with a centralized media library, from the Standard plan up.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Free plan available for a single brand with basic features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Purpose-built Agency tier with client portals and branded logins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$SmartQ predictive scheduling helps optimize post timing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Native integration with Zoho CRM and Zoho Desk$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Broad channel coverage including newer platforms like TikTok, Threads, and Bluesky$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Higher-tier features like SmartQ and CRM integration require Professional or Premium plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Agency plans are priced significantly higher than most competitors' entry tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Additional brands and team members are paid add-ons on most plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Some advanced channels (YouTube, WhatsApp) are limited to Premium and above$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Is Zoho Social free?$q$, $q$Yes, Zoho Social offers a free plan for 1 brand across 6 channels with basic scheduling and one team member.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$How much does Zoho Social cost?$q$, $q$Paid Business plans range from around 15 dollars per month (Standard) to around 65 dollars per month (Premium), while Agency plans start around 320 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$What is SmartQ in Zoho Social?$q$, $q$SmartQ is a predictive scheduling feature that recommends optimal posting times based on audience activity, available from the Professional plan up.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Does Zoho Social support TikTok?$q$, $q$Yes, TikTok is included among the channels supported on Standard plans and above.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Does Zoho Social have an agency plan?$q$, $q$Yes, dedicated Agency and Agency Plus plans support 10 and 20 brands respectively, with client portals and branded client logins.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Does Zoho Social integrate with Zoho CRM?$q$, $q$Yes, CRM integration is available starting on the Premium plan, linking social engagement to sales pipelines.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Is there a free trial for Zoho Social?$q$, $q$Yes, Zoho Social offers a 15-day free trial with no credit card required on paid plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$How many channels can Zoho Social manage per brand?$q$, $q$Coverage ranges from 6 channels on the Free plan up to 13-14 channels including YouTube and WhatsApp on the Premium plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Small business social scheduling$q$, $q$A single brand schedules and publishes content across core channels using SmartQ for optimal timing.$q$, $q$Small businesses and solo marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Team content approval workflows$q$, $q$Marketing teams draft, review, and approve posts collaboratively before publishing.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Agency client social management$q$, $q$Agencies manage dozens of client brands from one dashboard, with client portals and scheduled reporting.$q$, $q$Marketing and social media agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Free$q$, $q$0 dollars$q$, $q$n/a$q$, NULL, $q$["1 brand, 6 channels","1 team member","Dashboard and content calendar","Image editor"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Standard$q$, $q$Approximately 15 dollars per month (approximately 10 dollars per month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1 brand, up to 11 channels","Livestreaming","Bulk scheduler","RSS feeds","Media library"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Professional$q$, $q$Approximately 40 dollars per month$q$, $q$monthly or annual$q$, NULL, $q$["SmartQ predictive scheduling","Content approval workflows","Custom reports","Team collaboration tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Premium$q$, $q$Approximately 65 dollars per month$q$, $q$monthly or annual$q$, NULL, $q$["3 team members, up to 14 channels including YouTube and WhatsApp","CRM integrations","Lead generation and UTM tracking","Custom roles"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Agency$q$, $q$Approximately 320 dollars per month$q$, $q$monthly or annual$q$, NULL, $q$["10 brands","5 team members","Client portals and branded logins","Scheduled reporting"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$Agency Plus$q$, $q$Approximately 460 dollars per month$q$, $q$monthly or annual$q$, NULL, $q$["20 brands","5 team members","All Agency features","Higher brand capacity"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$overview$q$, $q$What Is Zoho Social$q$, 2, ARRAY[$q$Zoho Social is a social media management platform that lets businesses, marketers, and agencies plan, schedule, publish, and monitor content across multiple social channels from a single dashboard.$q$, $q$It is designed to serve a wide range of users, from individual creators and small teams managing one brand, to marketing agencies coordinating dozens of client accounts through dedicated Agency plans.$q$, $q$As part of the Zoho suite, Zoho Social integrates with Zoho CRM and Zoho Desk to connect social engagement with sales and support workflows, plus Canva for design.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SmartQ uses predictive analysis of audience activity to recommend the best times to publish content for maximum engagement.$q$, $q$Social monitoring tracks brand mentions, hashtags, and relevant keywords across supported channels, helping teams catch conversations and potential leads in real time.$q$, $q$Visual reports and custom analytics cover engagement metrics, follower growth, traffic sources, and click distribution.$q$, $q$Collaboration tools include content approval workflows, draft review, and team discussions, while Agency plans add client portals and branded client logins.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho Social's Free plan covers 1 brand and 6 channels for 1 user with basic scheduling tools.$q$, $q$Business plans scale from Standard (around 15 dollars per month) through Professional (around 40 dollars per month) to Premium (around 65 dollars per month), adding more channels, team members, SmartQ, approval workflows, and CRM integrations at each tier.$q$, $q$Agency plans start around 320 dollars per month for 10 brands (Agency) and go up to around 460 dollars per month for 20 brands (Agency Plus), both bundling client management features; annual billing saves up to 33 percent.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$HD video and audio meetings$q$, $q$Core video conferencing with screen sharing, breakout rooms, and virtual backgrounds.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$AI Companion$q$, $q$Generative AI assistant offering meeting summaries, smart replies, and task extraction.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Cloud and local recording$q$, $q$Record meetings to the cloud (paid plans) or locally, with searchable transcripts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Zoom Team Chat$q$, $q$Persistent messaging and channels integrated with the meetings platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Zoom Whiteboard$q$, $q$Collaborative visual whiteboarding usable during or outside of live meetings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Webinars and virtual events$q$, $q$Large-scale broadcast tools for hosting webinars and events, sold as add-ons.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Admin and security controls$q$, $q$Single sign-on, managed domains, and meeting security controls like waiting rooms and passcodes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Zoom Rooms hardware integration$q$, $q$Turns physical conference rooms into managed video meeting spaces.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Free Basic plan usable for unlimited one-on-one calls and 40-minute group meetings$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$AI Companion included at no extra cost on paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Widely adopted, making it easy for external participants to join without installation friction$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Reliable call quality and broad device and OS support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Scales from solo users to large enterprise deployments with dedicated Enterprise support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Free plan caps group meetings at 40 minutes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Advanced features like SSO and larger participant caps require Business tier or above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Add-on products (Phone, Webinars, Events, Contact Center) increase total cost beyond base meeting plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Enterprise pricing is not publicly listed and requires a custom sales quote$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Is Zoom free?$q$, $q$Yes, Zoom's Basic plan is free and supports meetings for up to 100 participants, though group meetings are capped at 40 minutes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$How much does Zoom Pro cost?$q$, $q$Zoom Pro costs around 13.33 dollars per user per month billed annually, or 16.99 dollars per user per month billed monthly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$What is Zoom AI Companion?$q$, $q$AI Companion is Zoom's generative AI assistant that provides meeting summaries, smart chat replies, and task extraction, included on paid plans at no extra cost.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$How many people can join a Zoom meeting?$q$, $q$The Basic and Pro plans support up to 100 participants, Business supports up to 300, and higher participant capacities are available through add-ons or Enterprise plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Who founded Zoom?$q$, $q$Zoom was founded in 2011 by Eric Yuan, a former Cisco WebEx engineer, and is headquartered in San Jose, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Is Zoom Phone included in Zoom's video plans?$q$, $q$No, Zoom Phone is a separate cloud calling product, though it is bundled into the Business Plus plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Does Zoom offer webinars?$q$, $q$Yes, Zoom Webinars and Zoom Events are separate add-on products for large-scale broadcasts and virtual events.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Is Zoom publicly traded?$q$, $q$Yes, Zoom Video Communications trades on NASDAQ under the ticker ZM.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Remote team meetings$q$, $q$Distributed teams hold daily standups, all-hands, and one-on-ones over HD video with recording and transcripts.$q$, $q$Remote and hybrid teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Client and sales calls$q$, $q$Sales and client-facing teams use screen sharing and recording to run demos and client meetings.$q$, $q$Sales and customer-facing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Large-scale webinars and events$q$, $q$Marketing and events teams broadcast webinars and virtual events to large external audiences using Zoom Webinars and Events add-ons.$q$, $q$Marketing and events teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Basic$q$, $q$0 dollars$q$, $q$n/a$q$, NULL, $q$["Up to 100 participants","40-minute cap on group meetings","Unlimited one-on-one meetings","Basic AI Companion features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Pro$q$, $q$Approximately 13.33 dollars per user per month annually (16.99 dollars monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Meetings up to 30 hours","Cloud recording","Basic admin controls","AI Companion"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Business$q$, $q$Approximately 18.33 dollars per user per month annually (21.99 dollars monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 300 participants","Single sign-on","Managed domains","Advanced admin controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Business Plus$q$, $q$Approximately 29 dollars per user per month annually$q$, $q$annual$q$, NULL, $q$["Everything in Business","Zoom Phone included","Workspace Reservation","Translated captions"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Unlimited cloud storage","Dedicated customer success manager","Higher participant caps","Executive business reviews"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$overview$q$, $q$What Is Zoom$q$, 2, ARRAY[$q$Zoom is a video conferencing and unified communications platform built by Zoom Video Communications, founded in 2011 by Eric Yuan and headquartered in San Jose, California. Its core video meeting product launched publicly in 2013 and became one of the most widely adopted communication tools in the world.$q$, $q$Beyond video calls, Zoom has expanded into a broader Zoom Workplace suite that includes team chat, whiteboarding, scheduling, and Zoom Phone for cloud calling, positioning itself as an all-in-one collaboration platform rather than a single-purpose meeting app.$q$, $q$Zoom serves everyone from individual freelancers hosting free one-on-one calls to large enterprises running company-wide webinars, virtual events, and contact centers on the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HD video and audio meetings support screen sharing, virtual backgrounds, breakout rooms, and cloud or local recording.$q$, $q$AI Companion, Zoom's generative AI assistant, provides automatic meeting summaries, smart chat replies, and follow-up task extraction across supported plans.$q$, $q$Zoom Team Chat and Whiteboard extend collaboration beyond live meetings for asynchronous work.$q$, $q$Zoom Rooms and Zoom Phone extend the platform into physical conference rooms and cloud telephony, respectively, as add-on products.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4a6f61d-c3a3-4ca6-b4af-abc327e0f762', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoom's Basic plan is free and supports meetings up to 100 participants with a 40-minute cap on group calls.$q$, $q$Pro (around 13.33 dollars per user per month annually) removes the time cap for meetings up to 30 hours; Business (around 18.33 dollars per user per month annually) adds SSO and supports up to 300 participants; and Business Plus (around 29 dollars per user per month annually) bundles in Zoom Phone and Workspace Reservation.$q$, $q$Enterprise pricing is custom and includes unlimited cloud storage and dedicated support for large organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Metered and unlimited calling plans$q$, $q$Choose pay-as-you-go or unlimited domestic calling depending on call volume.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Global Select international numbers$q$, $q$Provision phone numbers and unlimited calling across a large list of supported countries.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Auto-attendants and call routing$q$, $q$Multi-level menus and routing rules direct callers without a live receptionist.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Call queues$q$, $q$Manage high call volumes for support and sales teams with queue management profiles.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$AI Companion for calling$q$, $q$Automatic post-call summaries, task extraction, and voicemail prioritization on eligible plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Voicemail transcription$q$, $q$Converts voicemails to text for faster triage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$CRM automation$q$, $q$Native integration with platforms like Salesforce on Business Plus tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Power Pack analytics add-on$q$, $q$Real-time queue analytics, wallboard monitoring, and desktop receptionist console.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Flexible entry point with a low-cost Metered plan for light call volumes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Global Select simplifies international calling with local numbers in many countries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$AI Companion call summaries included on higher plans at no extra software needed$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Integrates natively with Zoom Meetings and Team Chat for unified communications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Scales from small teams to call-center-style operations with the Power Pack add-on$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Metered plan's pay-as-you-go outbound calling can be unpredictable for high-volume users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Advanced call center features require the separately priced Power Pack add-on$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Full AI Companion calling features are limited to specific bundled Workplace tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Global Select coverage, while broad, does not include every country$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Is Zoom Phone the same as Zoom Meetings?$q$, $q$No, Zoom Phone is a separate cloud business phone (VoIP) product from Zoom Video Communications, sold independently or bundled into higher Zoom Workplace plans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$How much does Zoom Phone cost?$q$, $q$Standalone plans start around 10.50 dollars per user per month for Metered calling and go up to around 20 dollars per user per month for Global Select, all billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Does Zoom Phone support international calling?$q$, $q$Yes, the Global Select plan provides international phone numbers and unlimited calling across a large list of supported countries.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Does Zoom Phone include AI features?$q$, $q$Yes, eligible plans include AI Companion features like post-call summaries, task extraction, and voicemail prioritization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Can Zoom Phone be bundled with Zoom Meetings?$q$, $q$Yes, Zoom Workplace Business Plus and Pro Plus tiers bundle Zoom Phone together with video meetings and team chat.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$What is the Zoom Phone Power Pack?$q$, $q$It is an add-on, around 25 dollars per user per month, that unlocks real-time queue analytics, wallboard monitoring, and a desktop receptionist console.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Does Zoom Phone integrate with CRM tools?$q$, $q$Yes, native CRM automation for platforms like Salesforce is available on the Business Plus tier.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$What is the difference between Metered and Unlimited Zoom Phone plans?$q$, $q$Metered charges pay-as-you-go rates per outbound call, while Unlimited includes unlimited domestic calling plus advanced call queue and auto-attendant features.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Replacing a legacy PBX phone system$q$, $q$Businesses migrate from on-premise phone hardware to cloud calling with auto-attendants and call routing.$q$, $q$SMBs modernizing office phone systems$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Global team calling$q$, $q$Distributed international teams get local phone numbers and unlimited calling through Global Select.$q$, $q$Global and multinational teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Unified video, chat, and calling$q$, $q$Organizations bundle Zoom Phone into Business Plus for a single subscription covering meetings, chat, and calling.$q$, $q$Mid-sized to large businesses standardizing communications$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$US and Canada Metered$q$, $q$Approximately 10.50 dollars per user per month annually$q$, $q$monthly or annual$q$, NULL, $q$["Pay-as-you-go outbound calling","Basic call routing","Voicemail"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$US and Canada Unlimited$q$, $q$Approximately 16 dollars per user per month annually (18 dollars month-to-month)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited domestic calling","Advanced call queue management","Multi-level auto-attendants","Basic AI Companion features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Global Select$q$, $q$Approximately 20 dollars per user per month annually (25 dollars month-to-month)$q$, $q$monthly or annual$q$, NULL, $q$["International phone numbers","Unlimited calling across supported countries","Global number provisioning"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Pro Plus (Workplace bundle)$q$, $q$Approximately 20.50 dollars per user per month annually$q$, $q$annual$q$, NULL, $q$["Zoom Phone included","AI Companion call transcription","10GB cloud recording storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Business Plus (Workplace bundle)$q$, $q$Approximately 24.50 dollars per user per month annually$q$, $q$annual$q$, NULL, $q$["Up to 250 users","300-participant meetings","Native CRM automation (e.g. Salesforce)"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$overview$q$, $q$What Is Zoom Phone$q$, 2, ARRAY[$q$Zoom Phone is Zoom's cloud-based business phone system, built to replace traditional on-premise PBX hardware with VoIP calling delivered through the same infrastructure that powers Zoom Meetings.$q$, $q$It is a separate, separately priced product from Zoom's core video conferencing plans, though it can be bundled into higher Zoom Workplace tiers like Business Plus for organizations that want unified video, chat, and calling under one subscription.$q$, $q$Zoom Phone targets businesses of all sizes looking to modernize their phone systems, from small teams needing simple metered calling to large enterprises requiring global numbers and advanced call center features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Auto-attendants and multi-level call routing direct incoming calls without a live receptionist, while call queues manage high call volumes for support and sales teams.$q$, $q$AI Companion features bring automatic post-call summaries, task extraction, and voicemail prioritization to eligible Zoom Phone plans.$q$, $q$Global Select plans provide international phone numbers and unlimited calling across supported countries, simplifying global team communications.$q$, $q$The optional Power Pack add-on delivers real-time queue analytics, wallboard monitoring, and a desktop receptionist console for contact center-style operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Standalone Zoom Phone plans include US and Canada Metered (around 10.50 dollars per user per month annually, pay-as-you-go outbound), US and Canada Unlimited (around 16 dollars per user per month annually), and Global Select (around 20 dollars per user per month annually) for international calling.$q$, $q$Zoom Phone is also bundled into Zoom Workplace tiers: Pro Plus (around 20.50 dollars per user per month annually) and Business Plus (around 24.50 dollars per user per month annually), which combine calling with video meetings, chat, and CRM automation.$q$, $q$An optional Power Pack add-on (around 25 dollars per user per month) adds advanced call center features like queue analytics and a receptionist console.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$B2B contact and company database$q$, $q$Large-scale database of verified business contacts and firmographic company data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Sales engagement automation (SalesOS)$q$, $q$Sequencing, dialing, and workflow tools built around the contact database for outbound prospecting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Conversation intelligence (Chorus)$q$, $q$Call recording and analysis to surface coaching opportunities and deal risk.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Intent data$q$, $q$Signals showing which accounts are actively researching relevant topics or competitors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Account-based marketing tools$q$, $q$Identify and target high-value accounts with coordinated marketing campaigns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Copilot AI$q$, $q$AI-driven account prioritization and outreach content generation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$CRM and sales tool integrations$q$, $q$Connects with Salesforce, HubSpot, and other CRM and engagement platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Data enrichment and workflows$q$, $q$Automatically enrich and route lead and account data into existing sales and marketing systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Large, frequently updated B2B contact and company database$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Combines data, engagement, and conversation intelligence in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$AI-driven Copilot helps prioritize accounts most likely to convert$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Deep integrations with major CRM and sales engagement tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Established, well-known brand in the sales intelligence category$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$No public self-serve pricing; requires a custom annual sales contract$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Significant per-seat add-on costs can push total spend well above the base package price$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$No monthly billing option, requiring an annual commitment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Total cost can be prohibitive for small businesses and startups$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Is ZoomInfo related to Zoom the video conferencing company?$q$, $q$No, ZoomInfo is a completely separate company. ZoomInfo is a B2B sales intelligence and data platform, while Zoom is a video conferencing company; they share no ownership.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$How much does ZoomInfo cost?$q$, $q$ZoomInfo requires a custom annual contract; industry estimates put SalesOS Professional around 14,995 dollars per year, Advanced around 24,995 dollars per year, and Elite at 39,995 dollars per year and above, before add-ons.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$What is ZoomInfo's ticker symbol?$q$, $q$ZoomInfo trades on NASDAQ under the ticker GTM, after changing from ZI in May 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$What is SalesOS?$q$, $q$SalesOS is ZoomInfo's flagship product combining contact and company search, sales engagement automation, conversation intelligence, and workflow tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Does ZoomInfo offer monthly billing?$q$, $q$No, ZoomInfo sells exclusively through annual contracts with no monthly billing option.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$When was ZoomInfo founded?$q$, $q$ZoomInfo traces back to Eliyon Technologies, founded in 2000, and took its current name and form after merging with DiscoverOrg in 2019.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Where is ZoomInfo headquartered?$q$, $q$ZoomInfo is headquartered in Vancouver, Washington.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$What is ZoomInfo Copilot?$q$, $q$Copilot is ZoomInfo's AI layer that prioritizes accounts and helps generate personalized outreach content based on buyer intent signals.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Outbound sales prospecting$q$, $q$Sales development teams use ZoomInfo's contact database and SalesOS engagement tools to build and run outbound campaigns.$q$, $q$B2B sales development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Account-based marketing$q$, $q$Marketing teams use intent data and firmographic data to identify and target high-value accounts.$q$, $q$B2B marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$Sales call coaching$q$, $q$Sales managers use Chorus conversation intelligence to review calls and coach reps on deal risk and messaging.$q$, $q$Sales managers and revenue operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$SalesOS Professional$q$, $q$Approximately 14,995 dollars per year (estimated)$q$, $q$annual contract$q$, NULL, $q$["Contact and company search","Basic sales engagement","CRM integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$SalesOS Advanced$q$, $q$Approximately 24,995 dollars per year (estimated)$q$, $q$annual contract$q$, NULL, $q$["Everything in Professional","Advanced workflows","Expanded data access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$SalesOS Elite$q$, $q$39,995 dollars per year and above (estimated)$q$, $q$annual contract$q$, NULL, $q$["Everything in Advanced","Conversation intelligence (Chorus)","Copilot AI features","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$overview$q$, $q$What Is ZoomInfo$q$, 2, ARRAY[$q$ZoomInfo is a B2B go-to-market intelligence platform that provides sales, marketing, and recruiting teams with company and contact data, buyer intent signals, and AI-driven insights to identify and engage prospects.$q$, $q$Despite the similar-sounding name, ZoomInfo is an entirely separate company from Zoom Video Communications, the video conferencing provider. ZoomInfo's roots trace to Eliyon Technologies (founded 2000), later rebranded after merging with DiscoverOrg in 2019, and it is headquartered in Vancouver, Washington.$q$, $q$In May 2025, the publicly traded company changed its NASDAQ ticker from ZI to GTM, reflecting a strategic shift toward positioning itself as a broader go-to-market intelligence platform rather than solely a contact database.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SalesOS, ZoomInfo's flagship product, combines contact and company search with sales engagement automation and workflow tools to power outbound and inbound prospecting.$q$, $q$Conversation intelligence, powered by ZoomInfo's Chorus acquisition, analyzes sales calls to surface coaching insights and deal risk signals.$q$, $q$Intent data and account-based marketing modules help marketing teams identify accounts actively researching relevant topics.$q$, $q$Copilot, ZoomInfo's AI layer, prioritizes accounts and helps generate personalized outreach content based on buyer signals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ZoomInfo does not publish self-serve pricing; all plans require a custom annual contract negotiated with the sales team, with no monthly billing option.$q$, $q$Industry pricing guides commonly cite SalesOS Professional starting around 14,995 dollars per year, Advanced around 24,995 dollars per year, and Elite at 39,995 dollars per year and above, plus per-seat add-on fees.$q$, $q$Additional modules such as intent data, ABM, Copilot, and Chorus conversation intelligence add to the base contract, with realistic total costs for mid-sized sales teams often landing between 25,000 and 60,000 dollars annually.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$OCI Distribution and Image Specification compliance$q$, $q$Strictly follows OCI standards for images stored purely in OCI format.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Single stateless binary$q$, $q$No external dependencies; runs without elevated privileges on cloud servers or edge devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Built-in security scanning$q$, $q$Vulnerability scanning included directly in the binary, no separate scanner service required.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Multiple authentication methods$q$, $q$Supports HTTP Basic, LDAP, and HTTP Bearer token authentication.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Garbage collection and deduplication$q$, $q$Automatically reclaims storage and avoids duplicate image layers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$OCI artifact support$q$, $q$Stores Helm charts, SBOMs, and image signatures alongside container images.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Replication and caching$q$, $q$Supports registry replication and caching for scale-out and edge deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Full and minimal build variants$q$, $q$Choose a feature-complete build or a minimal, security-focused build for smaller attack surface.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Free and open source under the Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Single binary with no external dependencies simplifies deployment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$CNCF Sandbox status signals community governance and cloud-native alignment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Broad OCI artifact support beyond just container images$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Runs on constrained hardware like a Raspberry Pi as well as production cloud infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Self-hosted only, requiring the user to manage infrastructure and updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$No commercial support contract or SLA from the project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Still in CNCF Sandbox stage, an earlier maturity level than Incubating or Graduated projects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Smaller ecosystem and community size compared to established registries like Docker Hub or Harbor$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Is Zot OCI Registry free?$q$, $q$Yes, Zot is free and open source under the Apache 2.0 license; costs are limited to whatever infrastructure you use to host it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$What is Zot's relationship to CNCF?$q$, $q$Zot was accepted as a CNCF Sandbox Project on December 13, 2022, with the Linux Foundation holding trademark rights over the project.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Does Zot work with Docker?$q$, $q$Yes, Zot supports standard Docker pull and push workflows as well as Podman, runc, and Helm.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$What OCI artifacts does Zot support besides container images?$q$, $q$Zot supports Helm charts, software bills of materials (SBOMs), and image signatures alongside standard container images.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Can Zot run on a Raspberry Pi?$q$, $q$Yes, its single-binary architecture with no external dependencies allows it to run on lightweight hardware including a Raspberry Pi.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Does Zot include security scanning?$q$, $q$Yes, vulnerability and security scanning are built directly into the binary rather than requiring a separate service.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$What authentication methods does Zot support?$q$, $q$Zot supports HTTP Basic authentication, LDAP, and HTTP Bearer token authentication.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Who maintains Zot?$q$, $q$Zot is maintained as an open-source community project under the project-zot GitHub organization, with Cisco noted as a sponsor and adopter, under CNCF Sandbox governance.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Lightweight self-hosted registry$q$, $q$Teams run Zot as a single binary to host container images without deploying a heavier registry platform.$q$, $q$Platform and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Edge and constrained deployments$q$, $q$Organizations deploy Zot on edge devices or small servers where a full registry stack is impractical.$q$, $q$Edge computing and IoT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Secure software supply chain$q$, $q$Teams store container images alongside SBOMs and signatures to support supply chain security requirements.$q$, $q$Security and compliance-focused engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$Open Source$q$, $q$0 dollars$q$, $q$n/a$q$, NULL, $q$["Full or minimal build","Self-hosted","Apache 2.0 license","Community support via GitHub and Slack"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$overview$q$, $q$What Is Zot OCI Registry$q$, 2, ARRAY[$q$Zot is an open-source, vendor-neutral, OCI-native container image and artifact registry, built purely on the OCI Distribution and Image Specifications rather than a proprietary internal format.$q$, $q$The project is a CNCF Sandbox Project, accepted on December 13, 2022, with the Linux Foundation holding trademark rights and Cisco noted as a sponsor and adopter in the project's ecosystem.$q$, $q$Unlike heavier registry platforms that require multiple services or external databases, Zot ships as a single, statically built binary with no external dependencies, making it easy to deploy anywhere from cloud infrastructure to edge devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zot bundles security scanning, authentication, authorization, garbage collection, and deduplication directly into the single binary, avoiding the need for separate add-on services.$q$, $q$It supports OCI artifacts beyond container images, including Helm charts, SBOMs, and image signatures, making it useful as a general artifact store for cloud-native supply chains.$q$, $q$Two build variants are available: a full-featured build and a minimal, security-hardened build for constrained or high-assurance environments.$q$, $q$It works seamlessly with standard container tooling such as Docker pull commands, Podman, runc, and Helm, requiring no changes to existing client workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zot is free and open source under the Apache 2.0 license, with no paid tiers or commercial licensing from the project itself.$q$, $q$Because it is self-hosted, actual cost depends on the infrastructure used to run it, ranging from a Raspberry Pi to production cloud servers.$q$, $q$Support is community-driven through GitHub issues, Slack channels, and official documentation rather than a paid support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11d0b0ec-f3a5-4cf0-b06c-e3d9fd102172', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Studio live production$q$, $q$Broadcast-quality live streaming with multi-speaker sessions, branded overlays, and real-time production controls.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Virtual and hybrid event support$q$, $q$Runs events fully virtual, fully in-person, or hybrid from the same platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Customizable exhibitor booths$q$, $q$Interactive booths with downloadable content, video chat, and lead capture forms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$AI-powered networking and matchmaking$q$, $q$Breakout rooms, one-on-one scheduling, gamification, and AI matchmaking for attendee connections.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$CRM and marketing automation integration$q$, $q$Bi-directional sync with Salesforce, HubSpot, Marketo, and Pardot for pipeline and engagement reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Branded registration and mobile apps$q$, $q$Fully brandable registration pages, virtual venues, and mobile event apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Analytics and reporting$q$, $q$Tracks attendee behavior, engagement metrics, and conversion data throughout the event lifecycle.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Scalable attendee capacity$q$, $q$Supports events from 100 attendees up to 25,000-plus for large-scale conferences.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Broadcast-quality Studio production without needing external production teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Strong bi-directional CRM integration ties events directly to pipeline reporting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Scales from small webinars to conferences with tens of thousands of attendees$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Modular platform covers virtual, hybrid, and in-person formats in one system$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$AI-powered matchmaking supports more meaningful attendee networking$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$No public self-serve pricing; requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Reported starting costs (thousands of dollars per year) may be out of reach for very small organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$As a newer company (founded 2020), it has a smaller track record than legacy event platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Advanced production and CRM features likely require higher-tier plans not detailed publicly$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$What is Zuddl used for?$q$, $q$Zuddl is used to run virtual, hybrid, and in-person B2B events, conferences, field events, and webinars from a single platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$When was Zuddl founded?$q$, $q$Zuddl was founded in 2020 by Bharath Varma and Vedha Sayyaparaju.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Where is Zuddl headquartered?$q$, $q$Zuddl is headquartered in San Francisco, California, with additional operations in Bangalore, India.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$How much does Zuddl cost?$q$, $q$Zuddl does not publish standard pricing; costs vary by event format, with third-party estimates ranging from roughly 80 dollars per month for basic usage to around 10,000 to 12,000 dollars per year for webinar and conference packages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Does Zuddl integrate with CRM tools?$q$, $q$Yes, Zuddl offers bi-directional integration with Salesforce, HubSpot, Marketo, and Pardot.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$What is Zuddl Studio?$q$, $q$Studio is Zuddl's live production module offering broadcast-quality streaming, multi-speaker sessions, and branded overlays.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$How many attendees can Zuddl support?$q$, $q$Zuddl is built to support events ranging from about 100 attendees to more than 25,000 for large-scale conferences.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Has Zuddl raised funding?$q$, $q$Yes, Zuddl went through Y Combinator's 2020 batch and has raised approximately 15.5 million dollars, including a 13.35 million dollar Series A round led by Alpha Wave Incubation and Qualcomm Ventures.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Large-scale B2B conferences$q$, $q$Organizers run multi-day conferences with thousands of attendees, combining live production with exhibitor booths and networking.$q$, $q$Enterprise marketing and events teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Pipeline-driven webinars$q$, $q$Marketing teams run webinar programs that sync attendee data directly into CRM and marketing automation for lead scoring.$q$, $q$B2B demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Hybrid field events$q$, $q$Organizations combine in-person attendance with a virtual audience for regional field events and user conferences.$q$, $q$Field marketing and community teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Webinar$q$, $q$Approximately 10,000 dollars per year (estimated)$q$, $q$annual$q$, NULL, $q$["Webinar hosting","Basic branding","Analytics and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Conferences$q$, $q$Approximately 12,000 dollars per year (estimated)$q$, $q$annual$q$, NULL, $q$["Studio live production","Exhibitor booths","Networking and matchmaking","CRM integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$Custom / Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Attendee volume-based pricing","Full CRM and marketing automation integration","Branded apps and venues","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$overview$q$, $q$What Is Zuddl$q$, 2, ARRAY[$q$Zuddl is a modular event management platform built for B2B marketers, associations, and conference organizers to run virtual, hybrid, and in-person events, along with standalone webinars, from a single unified system.$q$, $q$Founded in 2020 by Bharath Varma and Vedha Sayyaparaju and headquartered in San Francisco with operations in Bangalore, Zuddl emerged from Y Combinator's 2020 cohort and has raised approximately 15.5 million dollars in funding, including a Series A round led by Alpha Wave Incubation and Qualcomm Ventures.$q$, $q$The platform is designed to combine broadcast-quality production with real-time, bi-directional CRM integration, positioning it as a tool for marketers who need events to feed directly into pipeline and revenue reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Studio module provides live streaming with multi-speaker sessions, branded overlays, and production controls for TV-quality broadcasts without external crews.$q$, $q$Customizable virtual booths let exhibitors offer downloadable content, video chat, and lead capture forms to attendees.$q$, $q$Networking tools include breakout rooms, one-on-one meeting scheduling, gamification, and AI-powered matchmaking to drive meaningful attendee connections.$q$, $q$Deep CRM and marketing automation integrations with Salesforce, HubSpot, Marketo, and Pardot sync engagement and conversion data back into go-to-market systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('36a4b760-5ccb-4498-b325-7b29a847d7cf', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zuddl does not publish standardized public pricing; costs vary by event format and require a custom quote from Zuddl's sales team.$q$, $q$Third-party sources cite entry points around 80 dollars per month for lighter usage, roughly 10,000 dollars per year for Zuddl Webinar, and roughly 12,000 dollars per year for Zuddl Conferences.$q$, $q$Virtual event pricing is commonly based on annual attendee volume (for example, 2,000 to 3,000 attendees per year) rather than per-event or per-registration fees.$q$]::text[], 2);
